         .cpu_arch = .wasm32,
         .os_tag = .wasi,
         .cpu_features_add = std.Target.wasm.featureSet(&.{
             .bulk_memory,
             .sign_ext,
+            .simd128,  // Enable WASM SIMD for vectorized operations
         }),
     });

